var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"Meanwhile","TWN":"同一時間","SCN":"同一时间","DEU":"Meanwhile","FRA":"Meanwhile"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>로터스</color>\\n아마니 밸리, 코핀 컴퍼니 임시 지부","JPN":"管理局直轄都市<color=#ffd34c>ロータス</color>\\nアマニーバレー、コフィンカンパニーの臨時支部","ENG":"[[","TWN":"管理局直屬城市<color=#ffd34c>洛德斯</color>\\n阿瑪尼山谷，科芬公司臨時分部","SCN":"管理局直属城市<color=#ffd34c>洛德斯</color>\\n阿玛尼谷，科芬公司临时分部","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……그래, 대략적인 이야기는 이미 부사장에게 들었네.","JPN":"……ああ、大体の話はすでに副社長から聞いている。","ENG":"...I've already heard the broad strokes from the Vice President.","TWN":"……嗯嗯，事情我都聽副總說了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"스완의 계획을 저지하고, 노엘 양에게 닥쳤던 정보 말소를 해결한 모양이로군.","JPN":"スワンの計画を阻止し、ノエル君の情報抹消を解決したそうだな。","ENG":"Seems you stopped Swan's scheme and resolved the information erasure that threatened Noelle.","TWN":"看來你阻止了史旺的計畫，並解決了洛艾兒遇到的資訊抹消問題。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"쉽지 않은 일이었을 텐데 이번에도 고생이 많았네, 미나 양.","JPN":"簡単にはいかなかっただろう。今回もご苦労だった、ミナ君。","ENG":"It couldn't have been easy. Once again, you've done well, Mina.","TWN":"這次任務可不簡單，辛苦了，米娜。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나보다는 노엘이 더 고생 많았지. 애초에 나 혼자서 해결할 수 있는 문제도 아니었고.","JPN":"苦労ならノエルの方がしたと思うよ。そもそも私一人で解決できる問題じゃなかったし。","ENG":"Noelle had it worse than I did. It wasn't a problem I could have solved alone to begin with.","TWN":"我還好，洛艾兒比較辛苦。畢竟這不是我一個人能解決的問題。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트, 라이카, 에이미… 그밖에 많은 사람들의 도움 끝에 노엘을 구할 수 있었어.","JPN":"フェリセット、ライカ、エイミー……他にも、色んな人の協力があったからノエルを助けられた。","ENG":"Without Félicette, Laika, Amy... and so many others, I couldn't have saved her.","TWN":"在費莉塞特、萊卡、艾米……還有許多人的幫助下，終於救出了洛艾兒。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 결국 마지막에 스완은 놓쳐버리고 말았지만…….","JPN":"まあ、結局最後にスワンは捕まえられなかったけど……","ENG":"Though in the end, Swan slipped away again...","TWN":"嗯，但最後還是讓史旺逃掉了……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그녀는 부상을 입었어.","JPN":"だが、彼女は負傷している。","ENG":"But she was wounded.","TWN":"但是她也受傷了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"당분간은 그녀에 관해서는 신경 쓰지 않아도 괜찮을 걸세.","JPN":"彼女については、当分はそう意識せずともよいだろう。","ENG":"For the time being, we don't need to worry about her.","TWN":"暫時不用擔心她的事情。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무엇보다도 자네들이 무사히 귀환했다는 사실이 더 중요하지 않나?","JPN":"君たちが無事帰還したということが何より大事だ。そうだろう？","ENG":"What matters most is that you all returned alive.","TWN":"最重要的是你們平安回來了，這才是最重要的，不是嗎？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건 그렇지…….","JPN":"それはそうだけど……","ENG":"Yeah, that's true...","TWN":"那倒是……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응, 걱정해줘서 고마워, 사장님.","JPN":"うん。気にかけてくれてありがとう、社長。","ENG":"Thanks for worrying about me, Boss.","TWN":"嗯，謝謝你的關心，老闆。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 노엘 양도 고생이 많았어. 다시 코핀에 돌아온 걸 환영하네.","JPN":"そしてノエル君も大変ご苦労だった。再びコフィンに戻ってきたこと、歓迎しよう。","ENG":"And you as well, Noelle. Welcome back to Coffin.","TWN":"洛艾兒也辛苦了，歡迎再次回到科芬。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"후엥…! 보고 싶었어요, 사장님……!","JPN":"ふえーん……！　会いたかったです、社長……！","ENG":"Waaaah...! I missed you so much, Boss...!","TWN":"嗚嗚……！我好想你，老闆……！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이대로 영영 코핀 식구들을 못 보게 되면, 어떡하나 싶었다고요……!","JPN":"もう二度とコフィンのみんなに会えなくなったらどうしようって……！","ENG":"I was terrified I'd never see my Coffin family again...!","TWN":"我在想如果永遠見不到科芬的家人們該怎麼辦……！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나야 말로 자네를 다시 만날 수 있어서 기쁘다네.","JPN":"私の方こそ、君と再会できて嬉しい。","ENG":"I'm the one glad to see you again.","TWN":"能再次見到你，我很高興。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 세계가 존재할 수 있는 건, 자네가 이 세계를 포기하지 않았기 때문이니까.","JPN":"この世界が存在しているのは、君がこの世界を諦めなかったからだ。","ENG":"This world exists because you refused to give up on it.","TWN":"這個世界之所以能夠存在，是因為你沒有放棄這個世界。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 덕분에 나 역시 지금까지 내 모든 선택이 틀리지 않았음을 확신할 수 있었네.","JPN":"おかげで私も、今までの自分の選択は間違っていなかったと、確信を持つことができた。","ENG":"Thanks to you, I can believe that all my choices up to now weren't mistakes.","TWN":"因此，我才能確信自己至今為止所做的的所有選擇都沒有錯。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니 이 자리에서 다시금 감사를 전하지, 노엘 양.","JPN":"改めてお礼を言わせてくれ、ノエル君。","ENG":"So let me thank you once more, Noelle.","TWN":"所以在此我要再次感謝你，洛艾兒。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아니에요, 사장님.","JPN":"そんな、大袈裟ですよ、社長！","ENG":"No, Boss.","TWN":"不是的，老闆。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"제가 인간으로서 이 세계로부터 받아들여질 수 있었던 건, 모두 여러분 덕분인걸요.","JPN":"私が人間としてこの世界に受け入れてもらえたのは、全部皆さんのおかげです。","ENG":"If I could be accepted into this world as a human, it's only because of all of you.","TWN":"我能夠作為人類被這個世界所接受，全都是因為你們的緣故。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 저는 제 의지로 이 세계를 지킬 거예요. 흡!","JPN":"だから私は自分の意思でこの世界を守ります。ふうっ！","ENG":"That's why I'll protect this world by my own will. Hup!","TWN":"所以我會憑藉自己的意志守護這個世界。唔！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래… 그렇다면 다행이로군…….","JPN":"そうか……ならよかった……","ENG":"Good... I'm relieved to hear that...","TWN":"是嗎……那真是太好了……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네들이 있다면, 어떻게든 <color=#ffd34c>대비책</color>을 마련할 수 있을 테니까.","JPN":"君たちがいれば、なんとか<color=#ffd34c>対策</color>を練ることができる。","ENG":"With you here, we can still prepare some <color=#ffd34c>countermeasures</color>.","TWN":"只要有你們在，總會想到<color=#ffd34c>對策</color>的。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네? 대비책이라고요? 뭘 대비하는데요?","JPN":"え？　対策？　何に備えるんですか？","ENG":"Countermeasures? For what?","TWN":"什麼？你說對策？對策要幹嘛？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 설마 이번 사건과 관련된 중요한 이야기라는 게…….","JPN":"待って、まさか今回の事件に関わる重要な話っていうのは……","ENG":"Wait... don't tell me this has to do with the incident we just dealt with...","TWN":"等一下，難道說與本次事件有關的重要消息是指……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네, 미나 양.","JPN":"ああ、ミナ君。","ENG":"That's right, Mina.","TWN":"是的，米娜。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"적어도 자네들에게는 미리 말을 해두는 편이 좋을 것 같아서 말이지.","JPN":"せめて君たちには事前に伝えておいたほうがいいと思ってな。","ENG":"I felt it best to tell you two ahead of time.","TWN":"我覺得至少要先跟你們說會好點。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금부터 내가 할 이야기는 <color=#ffd34c>어떤 진실</color>에 관한 것일세.","JPN":"今から<color=#ffd34c>とある真実</color>について話そう。","ENG":"What I'm about to say concerns a <color=#ffd34c>certain truth</color>.","TWN":"接下來我要講的是關於<color=#ffd34c>某個真相</color>。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"바로 오퍼레이션 <color=#ffd34c>클리포트 게임</color>에 관한 진실이지.","JPN":"オペレーション<color=#ffd34c>クリフォトゲーム</color>の真実だ。","ENG":"The truth of Operation <color=#ffd34c>Qliphoth Game</color>.","TWN":"就是關於<color=#ffd34c>逆卡巴拉遊戲</color>的真相。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"클리포트 게임이라고……?","JPN":"クリフォトゲーム……？","ENG":"Qliphoth Game...?","TWN":"逆卡巴拉遊戲……？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};